sql:
SELECT driver_id, account_status, COUNT(*) OVER () AS total_active_drivers
FROM drivers
WHERE account_status = 'active';

external_knowledge:
- 'last day' refers to the 24-hour period ending at the current time; 
- 'login attempt records' include successful and failed login attempts, total attempts, and success rates; 
- 'ranked by their number of successful logins in descending order' implies that drivers with more successful logins are ranked higher.

sql:
SELECT COUNT(DISTINCT driver_id) AS total_drivers
FROM (
    SELECT driver_id FROM login_attempts
    UNION
    SELECT driver_id FROM transactions
);
